class Solution:
    def pyramidTransition(self, bottom: str, allowed: List[str]) -> bool:
        g = defaultdict(list)
        for a in allowed: g[a[:2]].append(a[2])
        def build(row):
            if len(row) == 1: return True
            nxt = []
            def dfs(i, cur):
                if i == len(row) - 1:
                    return build("".join(cur))
                for c in g[row[i:i+2]]:
                    cur.append(c)
                    if dfs(i+1, cur): return True
                    cur.pop()
                return False
            return dfs(0, [])
        return build(bottom)

