class Solution {
public:
    bool pyramidTransition(string bottom, vector<string>& allowed) {
        unordered_map<string, vector<char>> g;
        for(auto& a:allowed) g[a.substr(0,2)].push_back(a[2]);
        function<bool(string)> build = [&](string row){
            if(row.size()==1) return true;
            string nxt;
            function<bool(int)> dfs = [&](int i){
                if(i== (int)row.size()-1) return build(nxt);
                for(char c: g[row.substr(i,2)]){
                    nxt.push_back(c);
                    if(dfs(i+1)) return true;
                    nxt.pop_back();
                }
                return false;
            };
            return dfs(0);
        };
        return build(bottom);
    }
};

