bool pyramidTransition(char* bottom, char** allowed, int n) {
    if(!bottom[0]) return true;
    if(bottom[1]==0) return true;
    for(int i=0;i<n;i++){
        char key[3]={bottom[0],bottom[1],allowed[i][2]};
        if(strncmp(allowed[i],bottom,2)!=0) continue;
        char nxt[32]; nxt[0]=allowed[i][2]; strcpy(nxt+1,bottom+2);
        if(pyramidTransition(nxt,allowed,n)) return true;
    }
    return false;
}
